import React from 'react';
import { InlineCheckbox as CarbonInlineCheckbox } from '@carbon/react';

const InlineCheckbox = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonInlineCheckbox
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonInlineCheckbox>
    );
};

InlineCheckbox.defaultProps = {
    className: ''
};

export default InlineCheckbox;
